sql:
SELECT section_name, time, day, location
FROM course_sections
WHERE course_id = 0 AND semester = 'Spring' AND year = 2024 AND is_open = 1;

SELECT course_code
FROM courses
ORDER BY course_code;

SELECT course_id, AVG(rating) AS average_rating
FROM course_feedback
GROUP BY course_id;

SELECT rating, comments
FROM course_feedback
WHERE course_id = 0;

SELECT COUNT(section_id) AS section_count
  FROM course_sections
  WHERE course_id = 0;

SELECT course_code
FROM courses
ORDER BY course_code;

SELECT course_code
FROM courses
WHERE course_type_id = (SELECT course_type_id FROM course_types WHERE course_type_name = 'Lecture');

SELECT MAX(feedback_date) AS latest_feedback_date
FROM course_feedback
WHERE course_id = 0;

